mapper.sql:
SELECT ORG_ID , CMMN_CD_ID , LANG_CD , UP_CD , CD , CD_SEQ , CDNM , CD_EXPLN FROM TB_LMS_CMMN_CD WHERE 1=1
AND CD = #{cd}
AND UP_CD = #{upCd}

mapper.select:
		/*
			 SQL ID : OrgCodeLangDAO.select
			 설  명 : 코드 언어의 정보 조회
	 	*/

           AND LANG_CD = #{langCd}

mapper.insert:
/*
	 SQL ID : OrgCodeLangDAO.insert
	 설  명 : 코드 언어의 정보 등록
*/
INSERT INTO TB_ORG_CODE_LANG (
       LANG_CD
     , CTGRCD
     , CD
     , CDNM
     , CD_EXPLN
     , ORG_ID
) VALUES (
       #langCd}
     , #{codeCtgrCd}
     , #{codeCd}
     , #{codeNm}
     , #{codeDesc}
     , #{orgId}
)

mapper.update:
/*
	 SQL ID : OrgCodeLangDAO.update
	 설  명 : 코드 언어의 정보 수정
*/
UPDATE TB_ORG_CODE_LANG
   SET CDNM = #{codeNm}
     , CD_EXPLN = #{codeDesc}
 WHERE ORG_ID = #{orgId}
   AND CTGRCD = #{codeCtgrCd}
   AND CD = #{codeCd}
   AND LANG_CD = #{langCd}

mapper.delete:
	/*
		 SQL ID : OrgCodeLangDAO.delete
		 설  명 : 코드 언어의 정보 삭제
 	*/
	DELETE FROM TB_ORG_CODE_LANG
	 WHERE ORG_ID = #{orgId}
	   AND CTGRCD = #{codeCtgrCd}
	   AND CD = #{codeCd}
	   AND LANG_CD = #{langCd}

/*
	 SQL ID : OrgCodeLangDAO.deleteAll
	 설  명 : 코드 정보 하위의 코드 언어를 삭제
*/
DELETE FROM TB_ORG_CODE_LANG
 WHERE ORG_ID = #{orgId}
   AND CTGRCD = #{codeCtgrCd}
   AND CD = #{codeCd}

	/*
